        g_effect_ps_find_vector_intersection(query, query_len, result_buf, &result_len);

    v_result = caml_alloc(result_len, 0);
    for (int i = 0; i < result_len; i++)
        Store_field(v_result, i, Val_long(result_buf[i]));
    CAMLreturn(v_result);
