	);

	key_flush();

	if (Current_mission_num == 0 && !(Game_mode & GM_MULTI))		//only built-in mission, & not multi
	{
		int played = MOVIE_NOT_PLAYED;	//default is not played

		if (CurrentDataVersion == DataVer::DEMO)
