{
	int i;

	mprintf((0, "Highest object index=%d\n", Highest_object_index));

	for (i = 0; i <= Highest_object_index; i++)
	{
		if (Objects[i].type == OBJ_POWERUP)
			if (Objects[i].id == POW_FLAG_RED || Objects[i].id == POW_FLAG_BLUE)
				bash_to_shield(i, "Flag!!!!");
